import { NextResponse } from "next/server";
import { db } from "@/lib/db";

// Handle OTP Verification
export async function POST(req: Request) {
  try {
    const { email, otp } = await req.json();

    console.log(email, otp);
    

    // Find user with OTP
    const [user] = await db.query(
      "SELECT id, otp, otp_expires_at FROM users WHERE email = ?",
      [email]
    ) as any[];


    console.log(user[0]);
    

    if (!user) {
      return NextResponse.json({ error: "User not found" }, { status: 400 });
    }

    // Check OTP validity

    console.log("user ka otp", user[0].otp, " humne beja otp ", otp.toString());
    

    if (user[0].otp !== otp.toString()) {
      return NextResponse.json({ error: "Invalid OTP" }, { status: 400 });
    }

    if (new Date(user.otp_expires_at) < new Date()) {
      return NextResponse.json({ error: "OTP expired" }, { status: 400 });
    }

    // Mark user as verified
    await db.query("UPDATE users SET is_verified = 1 WHERE email = ?", [email]);

    return NextResponse.json({ message: "success" });

  } catch (error) {
    console.error(error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}
